# E2-Explorer/S06-T2-B-E3: completed from active packet iDo + starter
def dedup_report(rows, key='id'):
    seen = {}
    unique = []
    conflicts = []
    for r in rows:
        k = r[key]
        if k not in seen:
            seen[k] = r
            unique.append(r)
        elif seen[k] != r:
            conflicts.append({'id': k, 'a': seen[k], 'b': r})
    return {'unique': unique, 'conflicts': conflicts}
rows = [
    {'id': 'C001', 'v': 1},
    {'id': 'C002', 'v': 2},
    {'id': 'C001', 'v': 9},
]
print(dedup_report(rows))

